            sum_q[v] += a->q[i * NVAR + v];
        }
    }
    c->n = 1;
    c->vol[0] = sum_vol;
    double inv_n = 1.0 / (double)n;
    for (int v = 0; v < NVAR; v++) {
        c->q[v] = sum_q[v] * inv_n;
